import { Button } from "@/components/ui/button";
import Link from "next/link";

export function Nav() {
  return (
    <nav className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-8 py-4 bg-[oklch(0.10_0.015_50/0.92)] backdrop-blur-xl border-b border-[oklch(0.75_0.12_77/0.1)]">
      {/* ロゴ */}
      <Link href="/" className="flex items-baseline gap-0.5 no-underline">
        <span className="font-orbitron font-black text-xl tracking-wider [text-shadow:0_0_18px_oklch(0.75_0.12_77/0.45)] text-primary">
          JukuBox
        </span>
        <span className="font-orbitron font-bold text-sm text-secondary">
          .ai
        </span>
      </Link>

      {/* ナビリンク */}
      <div className="hidden md:flex items-center gap-8">
        {["機能", "使い方", "学習記録"].map((label) => (
          <a
            key={label}
            href={`#${label}`}
            className="text-sm tracking-wide transition-colors duration-200 text-muted-foreground"
          >
            {label}
          </a>
        ))}
      </div>

      {/* CTA */}
      <Button type="button" size="sm">
        無料で始める
      </Button>
    </nav>
  );
}

import { LandingDivider } from "@/app/_components/ui/landing-divider";

const links = [
  { label: "機能", href: "#機能" },
  { label: "使い方", href: "#使い方" },
  { label: "学習記録", href: "#学習記録" },
  { label: "ドキュメント", href: "#" },
  { label: "プライバシー", href: "#" },
  { label: "利用規約", href: "#" },
];

export function Footer() {
  return (
    <footer className="relative py-16 px-8 bg-background border-t border-[oklch(0.75_0.12_77/0.1)]">
      <div className="max-w-7xl mx-auto flex flex-col items-center gap-10">
        {/* ロゴ */}
        <div className="flex flex-col items-center gap-2">
          <div className="flex items-baseline gap-0.5">
            <span className="font-orbitron font-black text-2xl [text-shadow:0_0_18px_oklch(0.75_0.12_77/0.45)] text-primary">
              JukuBox
            </span>
            <span className="font-orbitron font-bold text-sm text-secondary">
              .ai
            </span>
          </div>
          <p className="font-noto-serif-jp text-xs text-center text-muted-foreground">
            AI エージェントと好きなことを好きなだけ学ぶ
          </p>
        </div>

        {/* リンク */}
        <nav className="flex flex-wrap justify-center gap-x-8 gap-y-3">
          {links.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="text-xs transition-colors duration-200 text-subtle-foreground"
            >
              {link.label}
            </a>
          ))}
        </nav>

        {/* セパレーター */}
        <LandingDivider />

        {/* コピーライト */}
        <div className="flex flex-col sm:flex-row items-center gap-4">
          <p className="font-space-mono text-xs text-subtle-foreground">
            © 2025 JukuBox.ai — All rights reserved.
          </p>
          <div className="flex items-center gap-2">
            {["Claude", "GPT-4o", "Gemini"].map((model) => (
              <span
                key={model}
                className="font-space-mono text-[10px] px-2 py-0.5 border border-[oklch(0.75_0.12_77/0.12)] text-subtle-foreground"
              >
                {model}
              </span>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
}

